.darma-loader-darma-custom-653-cls-1 {color: var(--loader-color, #f97316);
  --loader-secondary-color: #ef4444;
  --loader-bg: #f8fafc;

  fill: #f15a24;
  animation: darma-loader-darma-custom-653-cls1 4s ease infinite both;
}

@keyframes darma-loader-darma-custom-653-cls1 {
  0% {
    fill: #f15a24;
  }

  34% {
    fill: #ed1c24;
  }

  66% {
    fill: #f7931e;
  }

  100% {
    fill: #f15a24;
  }
}

.darma-loader-darma-custom-653-cls-1,
.darma-loader-darma-custom-653-cls-2,
.darma-loader-darma-custom-653-cls-3 {
  stroke-width: 0px;
}

.darma-loader-darma-custom-653-cls-2 {
  fill: #f7931e;
  animation: darma-loader-darma-custom-653-cls2 4s ease infinite both;
}

@keyframes darma-loader-darma-custom-653-cls2 {
  0% {
    fill: #f7931e;
  }

  34% {
    fill: #f15a24;
  }

  66% {
    fill: #ed1c24;
  }

  100% {
    fill: #f7931e;
  }
}

.darma-loader-darma-custom-653-cls-3 {
  fill: #ed1c24;
  animation: darma-loader-darma-custom-653-cls3 4s ease infinite both;
}

@keyframes darma-loader-darma-custom-653-cls3 {
  0% {
    fill: #ed1c24;
  }

  34% {
    fill: #f7931e;
  }

  66% {
    fill: #f15a24;
  }

  100% {
    fill: #ed1c24;
  }
}

#darma-loader-darma-custom-653-triangle {
  height: 128px;
  width: 128px;
  padding-top: 0;
  animation: darma-loader-darma-custom-653-triangle 4s both infinite;
}

@keyframes darma-loader-darma-custom-653-triangle {
  0% {
    transform: translateY(0px);
  }

  50% {
    transform: translateY(15px);
  }

  100% {
    transform: translateY(0px);
  }
}

